// Ēü┤ļØ╝ņØ┤ņ¢ĖĒŖĖ ņé¼ņØ┤ļō£ Mermaid ļĀīļŹöļ¦ü
// ```mermaid ņĮöļō£ ļĖöļĪØ(prism: code.language-mermaid)ņØä ņ░ŠņĢä SVG ļŗżņØ┤ņ¢┤ĻĘĖļ×©ņ£╝ļĪ£ ļ│ĆĒÖś.
// ļŗżĒü¼/ļØ╝ņØ┤ĒŖĖ Ēģīļ¦ł(data-theme)ņŚÉ ņŚ░ļÅÖļÉśļ®░, Ēģīļ¦ł ņĀäĒÖś ņŗ£ ņ×ÉļÅÖ ņ×¼ļĀīļŹöļ¦ü.

let mermaidPromise;
let renderSeq = 0;

function loadMermaid() {
  if (!mermaidPromise) {
    mermaidPromise = import('mermaid').then((mod) => mod.default || mod);
  }
  return mermaidPromise;
}

// translate(x, y) ļśÉļŖö translate(x) ĒśĢĒā£ņØś transform Ļ░ÆņŚÉņä£ [x, y] ņČöņČ£
function parseTranslate(transformStr) {
  if (!transformStr) return [0, 0];
  const m = transformStr.match(/translate\(\s*([+-]?\d*\.?\d+)\s*[, ]\s*([+-]?\d*\.?\d+)\s*\)/);
  if (m) return [parseFloat(m[1]), parseFloat(m[2])];
  const m1 = transformStr.match(/translate\(\s*([+-]?\d*\.?\d+)\s*\)/);
  if (m1) return [parseFloat(m1[1]), 0];
  return [0, 0];
}

// SVG ļĀīļŹö Ēøä cluster ņĀ£ļ¬®(.cluster-label)ņØ┤ ĒÖöņé┤Ēæ£(edgePaths) ļÆżļĪ£ ļ¼╗Ē×łļŖö ļ¼ĖņĀ£ ņłśņĀĢ.
// SVGļŖö ļ¼Ėņä£ ņł£ņä£ļīĆļĪ£ ĒÄśņØĖĒīģļÉśņ¢┤ clusters(ņĀ£ļ¬® ĒÅ¼ĒĢ©) ŌåÆ edges ņł£ņØ┤ļ»ĆļĪ£ ņĀ£ļ¬®ņØ┤ ĒÖöņé┤Ēæ£ņŚÉ Ļ░Ćļ”░ļŗż.
// ļĀīļŹö Ēøä .cluster-label ņÜöņåīļź╝ ļŻ©ĒŖĖ g ļ¦© ļüØņ£╝ļĪ£ ņØ┤ļÅÖĒĢ┤ Ļ░Ćņ×ź ļéśņżæņŚÉ ĒÄśņØĖĒīģļÉśĻ▓ī ĒĢ£ļŗż.
function bringClusterLabelsToFront(svgEl) {
  const rootG = svgEl.querySelector(':scope > g') || svgEl;
  const labels = Array.from(svgEl.querySelectorAll('.cluster > .cluster-label'));
  labels.forEach((label) => {
    const cluster = label.closest('.cluster');
    if (!cluster) return;
    const [cx, cy] = parseTranslate(cluster.getAttribute('transform'));
    const [lx, ly] = parseTranslate(label.getAttribute('transform'));
    label.setAttribute('transform', `translate(${cx + lx}, ${cy + ly})`);
    rootG.appendChild(label); // ļ¦© ļüØņ£╝ļĪ£ ņØ┤ļÅÖ ŌåÆ Ļ░Ćņ×ź ļéśņżæņŚÉ ĒÄśņØĖĒīģ(ĒÖöņé┤Ēæ£ ņ£ä)
  });
}

function currentMermaidTheme() {
  // ļŗżĒü¼ļ¬©ļō£ņŚÉņä£ļÅä 'default'(ļ░ØņØĆ) Ēģīļ¦łļĪ£ ļĀīļŹöĒĢ£ļŗż.
  // ļŗżņØ┤ņ¢┤ĻĘĖļ×© ņåīņŖżĻ░Ć styleļĪ£ ļ░ØņØĆ fill(Ēü¼ļ”╝/Ēīīļ×æ/ņŚ░ļæÉ)ņØä Ļ│ĀņĀĢ ņ¦ĆņĀĢĒĢśļŖöļŹ░,
  // dark Ēģīļ¦łļŖö ļģĖļō£ ĒģŹņŖżĒŖĖļź╝ ļ░ØĻ▓ī ĻĘĖļĀż "ļ░ØņØĆ ļ░░Ļ▓Į + ļ░ØņØĆ ĻĖĆņö©"ļĪ£ ņĢł ļ│┤ņØ┤ļŖö ļ¼ĖņĀ£ ļĢīļ¼Ė.
  // default Ēģīļ¦łļŖö ĒģŹņŖżĒŖĖļź╝ ņ¢┤ļæĪĻ▓ī ņ£Āņ¦ĆĒĢ┤ ņ¢┤ļ¢ż ļ¬©ļō£ņŚÉņä£ļÅä Ļ░ĆļÅģņä▒ņØ┤ ĒÖĢļ│┤ļÉ£ļŗż.
  return 'default';
}

async function renderOne(mermaid, source, target) {
  const id = `mermaid-svg-${Date.now()}-${renderSeq++}`;
  try {
    const { svg, bindFunctions } = await mermaid.render(id, source);
    target.innerHTML = svg;
    if (typeof bindFunctions === 'function') {
      bindFunctions(target);
    }
    const svgEl = target.querySelector('svg');
    if (svgEl) bringClusterLabelsToFront(svgEl);
  } catch (err) {
    // ļ¼Ėļ▓Ģ ņśżļźś ļō▒: ņøÉļ│Ė ņåīņŖżļź╝ ņĮöļō£ ļĖöļĪØņ£╝ļĪ£ ļģĖņČ£
    target.innerHTML = '';
    const pre = document.createElement('pre');
    pre.textContent = source;
    target.appendChild(pre);
    // eslint-disable-next-line no-console
    console.error('[mermaid] render failed:', err);
  }
}

export async function renderMermaid() {
  if (typeof window === 'undefined' || typeof document === 'undefined') return;

  // ņĢäņ¦ü ļĀīļŹöļÉśņ¦Ć ņĢŖņØĆ ņĮöļō£ ļĖöļĪØ
  const codeBlocks = Array.from(
    document.querySelectorAll('pre > code.language-mermaid, code.language-mermaid'),
  ).filter((code) => !code.closest('.mermaid-rendered'));

  // ņØ┤ļ»Ė ļĀīļŹöļÉ£ ļĖöļĪØ(Ēģīļ¦ł ņĀäĒÖś ņŗ£ ņ×¼ļĀīļŹö ļīĆņāü)
  const renderedWrappers = Array.from(document.querySelectorAll('.mermaid-rendered'));

  if (codeBlocks.length === 0 && renderedWrappers.length === 0) return;

  const mermaid = await loadMermaid();
  mermaid.initialize({
    startOnLoad: false,
    theme: currentMermaidTheme(),
    securityLevel: 'loose',
    fontFamily: "'Nanum Gothic', 'Pretendard', sans-serif",
    flowchart: {
      htmlLabels: true,
      // subgraph ņĀ£ļ¬®ņØ┤ cluster ņāüļŗ© ĒģīļæÉļ”¼ņŚÉ Ļ▓╣ņ╣śņ¦Ć ņĢŖļÅäļĪØ ņ£äņĢäļ×ś ņŚ¼ļ░▒ ļČĆņŚ¼
      subGraphTitleMargin: { top: 8, bottom: 12 },
    },
  });

  // ņŗĀĻĘ£ ļĖöļĪØ ļ│ĆĒÖś
  for (const code of codeBlocks) {
    const pre = code.closest('pre') || code;
    const source = code.textContent;
    const wrapper = document.createElement('div');
    wrapper.className = 'mermaid-rendered';
    wrapper.setAttribute('data-mermaid-source', source);
    pre.replaceWith(wrapper);
    // eslint-disable-next-line no-await-in-loop
    await renderOne(mermaid, source, wrapper);
  }

  // ĻĖ░ņĪ┤ ļĖöļĪØ ņ×¼ļĀīļŹö(Ēģīļ¦ł ļ░śņśü)
  for (const wrapper of renderedWrappers) {
    const source = wrapper.getAttribute('data-mermaid-source');
    if (!source) continue;
    // eslint-disable-next-line no-await-in-loop
    await renderOne(mermaid, source, wrapper);
  }
}

export function setupMermaidThemeObserver() {
  if (typeof window === 'undefined' || window.__mermaidThemeObserver) return;
  const observer = new MutationObserver((mutations) => {
    if (mutations.some((m) => m.attributeName === 'data-theme')) {
      renderMermaid();
    }
  });
  observer.observe(document.documentElement, { attributes: true, attributeFilter: ['data-theme'] });
  window.__mermaidThemeObserver = observer;
}
